<template>
  <div class="block-content" :style="blockStyle">
    <div class="inner" :style="innerStyle">
      <div class="columns" :style="gridStyle">
        <div
          v-for="(col, colIndex) in block.columns"
          :key="colIndex"
          class="column"
          :style="getColumnStyle(col.width)"
        >
          <component
            v-for="widget in col.widgets"
            :key="widget.id"
            :is="widgetRegistry.resolve(widget.type)"
            v-bind="widget.props"
            :widget="widget"
            :widgetId="widget.id"
            v-on="widgetListeners(widget.id)"
          />
        </div>
      </div>
    </div>
  </div>
</template>

<script setup lang="ts">
import { computed } from "vue";
import { widgetRegistry } from "../registry/widgetRegistry";

/* ─────────────────────────────
  TYPES
───────────────────────────── */
export interface Widget {
  id: string;
  type: string;
  props: Record<string, any>;
}

export interface Column {
  width: number;
  widgets: Widget[];
}

export interface Block {
  id: string;
  columns: Column[];
  backgroundColor?: string;
  backgroundOpacity?: number;
  contentWidth?: "sm" | "md" | "lg" | "full";
  paddingTop?: number;
  paddingBottom?: number;
}

/* ─────────────────────────────
  PROPS & EMITS
───────────────────────────── */
const props = defineProps<{
  block: Block;
}>();

const emit = defineEmits<{
  (e: "action", payload: any): void;
}>();

/* ─────────────────────────────
  SETTINGS
───────────────────────────── */
const COLUMN_GAP = 24;

/* ─────────────────────────────
  METHODS
───────────────────────────── */

/**
 * Returns a listener map for a given widget.
 * All events are normalised into a single @action payload
 * so PageRenderer / DocumentRenderer don't need to change.
 *
 * Shape emitted upstream:
 *   { widgetId, type, payload }
 *
 * Supported events:
 *   action       – generic passthrough (other widgets)
 *   update       – scheduler slot confirmed  → type: 'update'
 *   date-select  – scheduler date clicked    → type: 'date-select'
 *   month-change – scheduler month navigated → type: 'month-change'
 */
function widgetListeners(widgetId: string) {
  return {
    action: (payload: any) => emit("action", payload),

    update: (payload: any) => emit("action", { widgetId, type: "update", payload }),

    "date-select": (payload: any) =>
      emit("action", { widgetId, type: "date-select", payload }),

    "month-change": (payload: any) =>
      emit("action", { widgetId, type: "month-change", payload }),
  };
}

/**
 * Calculates column width adjusted for the gap.
 * For 2 columns (50%): calc(50% - 12px)
 * For 3 columns (33.33%): calc(33.33% - 16px)
 */
function getColumnStyle(percentage: number) {
  if (percentage >= 100) return { width: "100%" };
  const gapOffset =
    (COLUMN_GAP * (props.block.columns.length - 1)) / props.block.columns.length;
  return {
    width: `calc(${percentage}% - ${gapOffset}px)`,
  };
}

/* ─────────────────────────────
  STYLES
───────────────────────────── */
const innerStyle = computed(() => {
  const widths = {
    sm: "560px",
    md: "816px",
    lg: "1024px",
    full: "100%",
  };
  return {
    maxWidth: widths[props.block.contentWidth ?? "md"],
    margin: "0 auto",
    width: "100%",
  };
});

const blockStyle = computed(() => ({
  paddingTop: `${props.block.paddingTop ?? 60}px`,
  paddingBottom: `${props.block.paddingBottom ?? 60}px`,
  backgroundColor: props.block.backgroundColor || "transparent",
  opacity:
    props.block.backgroundOpacity !== undefined ? props.block.backgroundOpacity / 100 : 1,
}));

const gridStyle = computed(() => ({
  display: "flex",
  flexWrap: "wrap" as const,
  gap: `${COLUMN_GAP}px`,
  width: "100%",
  alignItems: "stretch",
}));
</script>

<style scoped>
.block-content {
  width: 100%;
  position: relative;
  box-sizing: border-box;
  padding-left: clamp(1rem, 5vw, 5rem);
  padding-right: clamp(1rem, 5vw, 5rem);
}
.inner {
  position: relative;
}
.columns {
  width: 100%;
}
.column {
  display: flex;
  flex-direction: column;
  box-sizing: border-box;
  flex-shrink: 0;
  gap: 1rem;
}
.column > * {
  width: 100%;
}
@media (max-width: 768px) {
  .columns {
    gap: 16px !important;
  }
  .column {
    width: 100% !important;
  }
}
</style>
