<template>
  <div class="fu-widget" :data-widget-id="widgetId" :style="widgetStyle">
    <div v-if="!eventTypeId" class="fu-empty">
      <span class="fu-empty__icon">📅</span>
      <p class="fu-empty__title">No event type selected</p>
      <p class="fu-empty__sub">Select an event type from the settings panel</p>
    </div>
    <div v-else class="fu-layout">
      <!-- LEFT -->
      <div class="fu-info">
        <p class="fu-info__name">{{ eventTypeName || "Event" }}</p>
        <div v-if="timezone" class="fu-info__meta">
          <span class="fu-info__icon">🌐</span>
          <span>{{ timezone }}</span>
        </div>
        <p v-if="description" class="fu-info__desc">{{ description }}</p>
        <div class="fu-tz" ref="tzRoot">
          <button
            class="fu-tz__trigger"
            type="button"
            @click="toggleTzDropdown"
            :aria-expanded="tzOpen"
          >
            <span class="fu-tz__globe">🌐</span>
            <span class="fu-tz__label">{{ selectedTzLabel }}</span>
            <span class="fu-tz__caret" :class="{ 'fu-tz__caret--open': tzOpen }">▾</span>
          </button>
          <transition name="fu-tz-pop">
            <div v-if="tzOpen" class="fu-tz__dropdown">
              <div class="fu-tz__search-wrap">
                <span class="fu-tz__search-icon"><Search :size="14" /></span>
                <input
                  ref="tzInput"
                  v-model="tzQuery"
                  class="fu-tz__search"
                  placeholder="Search city or country…"
                  autocomplete="off"
                  spellcheck="false"
                  @keydown.down.prevent="tzMove(1)"
                  @keydown.up.prevent="tzMove(-1)"
                  @keydown.enter.prevent="tzSelect(tzFiltered[tzHighlight])"
                  @keydown.esc="tzOpen = false"
                />
              </div>
              <ul class="fu-tz__list" ref="tzList">
                <li v-if="!tzFiltered.length" class="fu-tz__no-results">No results</li>
                <li
                  v-for="(opt, i) in tzFiltered"
                  :key="opt.value"
                  class="fu-tz__option"
                  :class="{
                    'fu-tz__option--active': opt.value === viewerTz,
                    'fu-tz__option--hi': i === tzHighlight,
                  }"
                  @mouseenter="tzHighlight = i"
                  @mousedown.prevent="tzSelect(opt)"
                >
                  <span class="fu-tz__opt-offset">{{ opt.offset }}</span>
                  <span class="fu-tz__opt-name">{{ opt.city }}</span>
                  <span class="fu-tz__opt-country">{{ opt.country }}</span>
                </li>
              </ul>
            </div>
          </transition>
        </div>
        <transition name="fu-slide">
          <div v-if="selectedSlot" class="fu-selected">
            <div class="fu-selected__label">Selected time</div>
            <div class="fu-selected__time">
              <span>📅</span>
              <span>{{ formatSelectedDate }}</span>
            </div>
            <div class="fu-selected__time">
              <span>🕐</span>
              <span
                >{{ convertSlotTime(selectedSlot) }} –
                {{ convertSlotEnd(selectedSlot) }}</span
              >
            </div>
          </div>
        </transition>
      </div>
      <!-- RIGHT -->
      <div class="fu-right">
        <FullCalendar :key="calKey" ref="calRef" :options="calOptions" class="fu-fc" />
        <transition name="fu-slide-right">
          <div v-if="selectedDate" class="fu-slots">
            <div class="fu-slots__header">
              <p class="fu-slots__heading">{{ formatDateLabel(selectedDate) }}</p>
              <button class="fu-slots__close" @click.stop="closeSlots">✕</button>
            </div>
            <div v-if="slotsLoading" class="fu-slots__loading">
              <span class="fu-slots__spinner" />
            </div>
            <div v-else-if="slots && slots.length" class="fu-slots__list">
              <div v-for="slot in slots" :key="slot.id" class="fu-slot">
                <button
                  class="fu-slot__time"
                  :class="{ 'fu-slot__time--chosen': selectedSlot?.id === slot.id }"
                  @click.stop="selectedSlot = slot"
                >
                  {{ convertSlotTime(slot) }}
                </button>
                <transition name="fu-confirm-pop">
                  <button
                    v-if="selectedSlot?.id === slot.id"
                    class="fu-slot__confirm"
                    :class="{ 'fu-slot__confirm--done': confirmedSlot?.id === slot.id }"
                    @click.stop="confirm"
                  >
                    {{ confirmedSlot?.id === slot.id ? "✓ Selected" : "Confirm" }}
                  </button>
                </transition>
              </div>
            </div>
            <p v-else class="fu-slots__empty">No availability</p>
          </div>
        </transition>
      </div>
    </div>
  </div>
</template>

<script setup lang="ts">
import { ref, computed, watch, nextTick, onMounted, onBeforeUnmount } from "vue";
import FullCalendar from "@fullcalendar/vue3";
import dayGridPlugin from "@fullcalendar/daygrid";
import interactionPlugin from "@fullcalendar/interaction";
import { getTimeZones } from "@vvo/tzdb";
import { Search } from "lucide-vue-next";

export interface FuSlot {
  id: string;
  start: string; // ISO 8601 UTC e.g. "2026-06-10T09:00:00.000Z"
  end: string; // ISO 8601 UTC e.g. "2026-06-10T09:30:00.000Z"
}

export interface FuSchedulerStyle {
  bgColor?: string;
  bgOpacity?: number;
  borderRadius?: number;
  shadow?: number;
  dayColor?: string;
  dayShape?: "circle" | "square";
}

export interface FuSchedulerUpdatePayload {
  bookedSlot: FuSlot;
}
export interface FuDateSelectPayload {
  date: string;
}
export interface FuMonthChangePayload {
  year: number;
  month: number;
}

const props = defineProps<{
  widgetId?: string | number;
  eventTypeId?: string | number;
  eventTypeName?: string;
  description?: string;
  timezone?: string;
  style?: FuSchedulerStyle;
  availableDates?: string[];
  slots?: FuSlot[];
  slotsLoading?: boolean;
}>();

const emit = defineEmits<{
  (e: "update", payload: FuSchedulerUpdatePayload): void;
  (e: "date-select", payload: FuDateSelectPayload): void;
  (e: "month-change", payload: FuMonthChangePayload): void;
}>();

// ── Timezone data ─────────────────────────────────────────────────────────
interface TzOpt {
  value: string;
  offset: string;
  city: string;
  country: string;
  searchIndex: string;
}

const allTzOpts = computed(() =>
  getTimeZones().map((tz) => {
    const city =
      tz.mainCities?.[0] || tz.name.split("/").pop()?.replace(/_/g, " ") || tz.name;
    const offsetMinutes = tz.rawOffsetInMinutes ?? 0;
    const sign = offsetMinutes >= 0 ? "+" : "-";
    const abs = Math.abs(offsetMinutes);
    const hh = String(Math.floor(abs / 60)).padStart(2, "0");
    const mm = String(abs % 60).padStart(2, "0");
    const offset = `UTC${sign}${hh}:${mm}`;
    return {
      value: tz.name,
      offset,
      city,
      country: "",
      searchIndex: [tz.name, tz.abbreviation, city, tz.group, offset]
        .join(" ")
        .toLowerCase(),
    };
  })
);

function detectTimezone(): string {
  try {
    return Intl.DateTimeFormat().resolvedOptions().timeZone || "UTC";
  } catch {
    return "UTC";
  }
}

const viewerTz = ref<string>(detectTimezone());
const tzOpen = ref(false);
const tzQuery = ref("");
const tzHighlight = ref(0);
const tzRoot = ref<HTMLElement | null>(null);
const tzInput = ref<HTMLInputElement | null>(null);
const tzList = ref<HTMLElement | null>(null);

const selectedTzLabel = computed<string>(() => {
  const found = allTzOpts.value.find((o) => o.value === viewerTz.value);
  return found ? `${found.offset} · ${found.city}` : viewerTz.value;
});

const tzFiltered = computed<TzOpt[]>(() => {
  const q = tzQuery.value.trim().toLowerCase();
  return q ? allTzOpts.value.filter((o) => o.searchIndex.includes(q)) : allTzOpts.value;
});

async function toggleTzDropdown() {
  tzOpen.value = !tzOpen.value;
  if (tzOpen.value) {
    tzQuery.value = "";
    tzHighlight.value = Math.max(
      0,
      tzFiltered.value.findIndex((o) => o.value === viewerTz.value)
    );
    await nextTick();
    tzInput.value?.focus();
    scrollHighlightIntoView();
  }
}

function tzSelect(opt: TzOpt | undefined) {
  if (!opt) return;
  viewerTz.value = opt.value;
  tzOpen.value = false;
  tzQuery.value = "";
}

function tzMove(dir: 1 | -1) {
  const len = tzFiltered.value.length;
  if (!len) return;
  tzHighlight.value = (tzHighlight.value + dir + len) % len;
  scrollHighlightIntoView();
}

function scrollHighlightIntoView() {
  nextTick(() => {
    const li = tzList.value?.children[tzHighlight.value] as HTMLElement | undefined;
    li?.scrollIntoView({ block: "nearest" });
  });
}

watch(tzFiltered, () => {
  tzHighlight.value = 0;
});

function onDocClick(e: MouseEvent) {
  if (tzRoot.value && !tzRoot.value.contains(e.target as Node)) tzOpen.value = false;
}

onMounted(() => document.addEventListener("mousedown", onDocClick));
onBeforeUnmount(() => document.removeEventListener("mousedown", onDocClick));

// ── Widget style ──────────────────────────────────────────────────────────
const widgetStyle = computed(() => {
  const s = props.style || {};
  const hex = s.bgColor || "#ffffff";
  const opacity = (s.bgOpacity ?? 100) / 100;
  const toVal = (v: string) => {
    const n = parseInt(v, 16);
    return isNaN(n) ? 255 : n;
  };
  const r = toVal(hex.slice(1, 3)),
    g = toVal(hex.slice(3, 5)),
    b = toVal(hex.slice(5, 7));
  const shadows = [
    "none",
    "0 1px 4px rgba(0,0,0,0.07)",
    "0 2px 12px rgba(0,0,0,0.10)",
    "0 4px 20px rgba(0,0,0,0.13)",
    "0 8px 32px rgba(0,0,0,0.16)",
  ];
  const dayColor = s.dayColor || "#4f46e5";
  const isCircle = (s.dayShape || "circle") === "circle";
  return {
    backgroundColor: `rgba(${r},${g},${b},${opacity})`,
    "--widget-bg": `rgba(${r},${g},${b},${opacity})`,
    borderRadius: `${s.borderRadius ?? 12}px`,
    boxShadow: shadows[Math.min(s.shadow ?? 2, 4)],
    "--sch-day-color": dayColor,
    "--sch-day-color-light": dayColor + "22",
    "--sch-day-color-mid": dayColor + "44",
    "--sch-day-radius": isCircle ? "50%" : "10px",
    "--sch-day-size": isCircle ? "32px" : "40px",
  };
});

// ── Available dates set ───────────────────────────────────────────────────
const availableDatesSet = computed<Set<string>>(
  () => new Set(props.availableDates ?? [])
);

const dotEvents = computed(() =>
  [...availableDatesSet.value].map((d) => ({
    id: `dot-${d}`,
    date: d,
    display: "background",
    classNames: ["sch-avail-bg"],
  }))
);

// ── Today string in local timezone (YYYY-MM-DD) ───────────────────────────
function getTodayStr(): string {
  return new Date().toLocaleDateString("en-CA"); // always YYYY-MM-DD in local tz
}

// ── Selection state ───────────────────────────────────────────────────────
const selectedDate = ref<string | null>(null);
const selectedSlot = ref<FuSlot | null>(null);
const confirmedSlot = ref<FuSlot | null>(null);
const calRef = ref<InstanceType<typeof FullCalendar> | null>(null);
const calKey = computed(() => `cal-${props.eventTypeId}`);

watch(selectedDate, () => {
  selectedSlot.value = null;
});
watch(
  () => props.slots,
  () => {
    selectedSlot.value = null;
  }
);
watch(
  () => props.eventTypeId,
  () => {
    selectedDate.value = null;
    selectedSlot.value = null;
    viewerTz.value = detectTimezone();
  }
);

function closeSlots(): void {
  selectedDate.value = null;
  selectedSlot.value = null;
  setTimeout(() => calRef.value?.getApi?.()?.updateSize(), 260);
}

// ── FullCalendar options ──────────────────────────────────────────────────
const calOptions = computed(() => ({
  plugins: [dayGridPlugin, interactionPlugin],
  initialView: "dayGridMonth",
  headerToolbar: { left: "prev", center: "title", right: "next" },
  height: "auto",
  fixedWeekCount: false,
  showNonCurrentDates: false,
  events: dotEvents.value,

  datesSet({ view }: { view: { currentStart: Date } }) {
    const d = view.currentStart;
    emit("month-change", { year: d.getFullYear(), month: d.getMonth() + 1 });
  },

  dayCellClassNames({ date }: { date: Date }) {
    const d = [
      date.getFullYear(),
      String(date.getMonth() + 1).padStart(2, "0"),
      String(date.getDate()).padStart(2, "0"),
    ].join("-");

    const isPast = d < getTodayStr();
    const classes: string[] = [];

    if (availableDatesSet.value.has(d)) {
      classes.push(isPast ? "sch-day--past" : "sch-day--available");
    } else {
      // Not in availableDates — always grey, never clickable
      classes.push("sch-day--past");
    }

    if (d === selectedDate.value) classes.push("sch-day--selected");
    return classes;
  },

  dateClick({ dateStr }: { dateStr: string }) {
    if (dateStr < getTodayStr()) return;
    if (!availableDatesSet.value.has(dateStr)) return;
    selectedDate.value = dateStr;
    emit("date-select", { date: dateStr });
    setTimeout(() => calRef.value?.getApi?.()?.updateSize(), 260);
  },

  selectable: false,
  editable: false,
}));

// ── Confirm ───────────────────────────────────────────────────────────────
function confirm(): void {
  if (!selectedSlot.value) return;
  confirmedSlot.value = selectedSlot.value;
  emit("update", { bookedSlot: selectedSlot.value });
}

// ── Time helpers ──────────────────────────────────────────────────────────
function formatDateLabel(dateStr: string): string {
  if (!dateStr) return "";
  const [y, m, d] = dateStr.split("-").map(Number);
  return new Date(y, m - 1, d).toLocaleDateString("en-GB", {
    weekday: "long",
    day: "numeric",
    month: "long",
  });
}

const formatSelectedDate = computed<string>(() => {
  if (!selectedSlot.value?.start) return formatDateLabel(selectedDate.value || "");
  return new Date(selectedSlot.value.start).toLocaleDateString("en-GB", {
    weekday: "long",
    day: "numeric",
    month: "long",
  });
});

function convertTime(isoDate: string, tz: string): string {
  if (!isoDate) return "";
  try {
    return new Date(isoDate).toLocaleTimeString("en-US", {
      timeZone: tz || "UTC",
      hour: "numeric",
      minute: "2-digit",
      hour12: true,
    });
  } catch {
    return "";
  }
}

function convertSlotTime(slot: FuSlot): string {
  return slot?.start ? convertTime(slot.start, viewerTz.value) : "";
}

function convertSlotEnd(slot: FuSlot): string {
  return slot?.end ? convertTime(slot.end, viewerTz.value) : "";
}
</script>

