<template>
  <div class="fu-listview" ref="listviewRef">
    <div class="fu-listview__table-wrapper customScrollBar" ref="tableWrapper">
      <table>
        <!-- HEADER -->
        <thead v-if="showHeader">
          <tr>
            <th
              v-if="options?.selectable"
              class="fu-listview__th fu-listview__th--checkbox"
            >
              <div v-if="loading" class="fu-skeleton-cell fu-skeleton-cell--checkbox" />
              <FusionCheckbox v-else v-model="allSelected" size="sm" />
            </th>

            <th
              v-for="(col, index) in internalColumns"
              :key="col.key"
              :style="{ width: col.width || 'auto' }"
              class="fu-listview__th"
              :class="`align-${col.textAlign || 'justify'}`"
            >
              <div
                class="fu-listview__th-content"
                :class="`align-${col.textAlign || 'justify'}`"
              >
                <!-- skeleton label -->
                <div v-if="loading" class="fu-skeleton-cell fu-skeleton-cell--header" />

                <!-- real label -->
                <div
                  v-else
                  class="fu-listview__th-sortable"
                  :class="{
                    'is-sortable': !!col.sortable,
                    'is-active': activeSortKey === col.key,
                  }"
                  :role="col.sortable ? 'button' : undefined"
                  :tabindex="col.sortable ? 0 : -1"
                  @click="onHeaderClick(col)"
                  @keydown.enter.prevent="onHeaderClick(col)"
                  @keydown.space.prevent="onHeaderClick(col)"
                >
                  <component
                    v-if="col.icon"
                    :is="col.icon"
                    class="fu-listview__th-icon"
                  />
                  <span class="fu-listview__th-label">{{ col.label }}</span>

                  <!-- sort indicator: always shown on sortable cols -->
                  <span v-if="col.sortable" class="fu-listview__sort-indicator">
                    <template v-if="activeSortKey === col.key">
                      {{ activeSortDirection === "asc" ? "▲" : "▼" }}
                    </template>
                    <template v-else>⇅</template>
                  </span>
                </div>

                <span
                  v-if="options?.resizeColumn && !loading"
                  class="fu-listview__resize-handle"
                  @mousedown.stop="startResize($event, index)"
                ></span>
              </div>
            </th>
          </tr>
        </thead>

        <!-- BODY: LOADING -->
        <tbody v-if="loading">
          <tr
            v-for="i in skeletonRows"
            :key="`skeleton-${i}`"
            class="fu-listview__row fu-listview__row--skeleton"
          >
            <td
              v-if="options?.selectable"
              class="fu-listview__td fu-listview__td--checkbox"
            >
              <div class="fu-skeleton-cell fu-skeleton-cell--checkbox" />
            </td>
            <td
              v-for="col in internalColumns"
              :key="`skeleton-${i}-${col.key}`"
              class="fu-listview__td"
              :style="{ width: col.width }"
            >
              <div
                class="fu-skeleton-cell"
                :style="{ width: skeletonWidth(i, col.key) }"
              />
            </td>
          </tr>
        </tbody>

        <!-- BODY: REAL DATA -->
        <tbody v-else>
          <tr
            v-for="row in rows"
            :key="row[rowKey]"
            class="fu-listview__row"
            @click="handleRowClick(row)"
          >
            <td
              v-if="options?.selectable"
              class="fu-listview__td fu-listview__td--checkbox"
              @click.stop
            >
              <FusionCheckbox
                v-model="row.__selected"
                @change="emitSelectionChange"
                size="sm"
                :disabled="!isSelectable(row)"
              />
            </td>
            <slot name="tableRow" :row="row">
              <td
                v-for="col in internalColumns"
                :key="col.key"
                class="fu-listview__td"
                :style="{ width: col.width }"
                :class="`align-${col.textAlign || 'justify'}`"
              >
                <slot :name="`cell-${col.key}`" :row="row" :col="col">
                  <span class="fu-listview__cell">{{ row[col.key] }}</span>
                </slot>
              </td>
            </slot>
          </tr>
        </tbody>
      </table>
    </div>
  </div>
</template>

<script setup lang="ts">
import { ref, watch, computed, onMounted, onBeforeUnmount } from "vue";
import FusionCheckbox from "@/components/checkbox/FusionCheckbox.vue";

export type SortDirection = "asc" | "desc";

export interface ListColumn {
  label: string;
  key: string;
  width?: string;
  icon?: any;
  textAlign?: "start" | "center" | "end" | "justify";
  sortable?: boolean;
}

const props = defineProps<{
  columns: ListColumn[];
  rows: Record<string, any>[];
  rowKey: string;
  showHeader?: boolean;
  loading?: boolean;
  skeletonRows?: number;
  sort?: {
    key: string | null;
    direction: SortDirection;
  } | null;
  options?: {
    onRowClick?: (row: any) => void;
    selectable?: boolean;
    resizeColumn?: boolean;
    sortable?: boolean;
    isRowSelectable?: (row: any) => boolean;
  };
}>();

const emit = defineEmits<{
  (e: "row-selected", selectedRows: any[]): void;
  (e: "row-clicked", clickedRow: any): void;
  (e: "sort-change", payload: { key: string; direction: SortDirection }): void;
}>();

/* -----------------------------
   SKELETON WIDTHS
-------------------------------- */
const widthSets = [
  ["55%", "70%", "40%", "65%", "50%"],
  ["75%", "45%", "80%", "55%", "60%"],
  ["60%", "80%", "50%", "70%", "45%"],
  ["45%", "65%", "75%", "40%", "70%"],
  ["70%", "50%", "60%", "80%", "55%"],
];

function skeletonWidth(rowIndex: number, colKey: string): string {
  const colIndex = props.columns.findIndex((c) => c.key === colKey) % 5;
  return widthSets[(rowIndex - 1) % widthSets.length][colIndex];
}

/* -----------------------------
   INTERNAL STATE
-------------------------------- */
const skeletonRows = computed(() => props.skeletonRows ?? 8);

const internalColumns = ref(
  props.columns.map((col) => ({
    ...col,
    width: col.width || "150px",
    textAlign: col.textAlign || "justify",
    sortable: !!col.sortable,
  }))
);

const allSelected = ref(false);
const listviewRef = ref<HTMLElement | null>(null);
const tableWrapper = ref<HTMLElement | null>(null);
const internalSortKey = ref<string | null>(null);
const internalSortDirection = ref<SortDirection>("asc");

const isControlledSort = computed(() => !!props.sort);

const activeSortKey = computed(() =>
  isControlledSort.value ? props.sort?.key ?? null : internalSortKey.value
);

const activeSortDirection = computed(() =>
  isControlledSort.value ? props.sort?.direction ?? "asc" : internalSortDirection.value
);

const showHeader = props.showHeader ?? true;
const isSortingEnabled = () => props.options?.sortable !== false;

/* -----------------------------
   SELECTION
-------------------------------- */
function isSelectable(row: any) {
  if (!props.options?.selectable) return false;
  if (props.options?.isRowSelectable) return props.options.isRowSelectable(row);
  return true;
}

function emitSelectionChange() {
  const selected = props.rows.filter((r) => r.__selected && isSelectable(r));
  emit("row-selected", selected);
}

watch(allSelected, (val) => {
  if (!props.options?.selectable) return;
  props.rows.forEach((row) => {
    if (isSelectable(row)) row.__selected = val;
  });
  emitSelectionChange();
});

/* -----------------------------
   SORTING
-------------------------------- */
function onHeaderClick(col: { key: string; sortable?: boolean }) {
  if (!isSortingEnabled()) return;
  if (!col.sortable) return;

  const currentKey = activeSortKey.value;
  const currentDirection = activeSortDirection.value;
  let newDirection: SortDirection = "asc";

  if (currentKey === col.key) {
    newDirection = currentDirection === "asc" ? "desc" : "asc";
  }

  if (!isControlledSort.value) {
    internalSortKey.value = col.key;
    internalSortDirection.value = newDirection;
  }

  emit("sort-change", { key: col.key, direction: newDirection });
}

/* -----------------------------
   ROW CLICK
-------------------------------- */
function handleRowClick(row: any) {
  emit("row-clicked", row);
  props.options?.onRowClick?.(row);
}

/* -----------------------------
   RESIZE
-------------------------------- */
let resizingIndex: number | null = null;
let startX = 0;
let startWidth = 0;

function startResize(e: MouseEvent, index: number) {
  if (!props.options?.resizeColumn) return;
  resizingIndex = index;
  startX = e.clientX;
  startWidth = parseInt(internalColumns.value[index].width as string, 10);
  document.addEventListener("mousemove", onResize);
  document.addEventListener("mouseup", stopResize);
}

function onResize(e: MouseEvent) {
  if (resizingIndex === null) return;
  const delta = e.clientX - startX;
  internalColumns.value[resizingIndex].width = `${Math.max(60, startWidth + delta)}px`;
}

function stopResize() {
  resizingIndex = null;
  document.removeEventListener("mousemove", onResize);
  document.removeEventListener("mouseup", stopResize);
}

/* -----------------------------
   SCROLL FIX
-------------------------------- */
function wakeScroll() {
  const el = tableWrapper.value;
  if (!el) return;
  el.style.overflowY = "hidden";
  requestAnimationFrame(() => {
    el.style.overflowY = "auto";
  });
}

onMounted(() => {
  wakeScroll();
  window.addEventListener("resize", wakeScroll);
});

onBeforeUnmount(() => {
  window.removeEventListener("resize", wakeScroll);
  document.removeEventListener("mousemove", onResize);
  document.removeEventListener("mouseup", stopResize);
});
</script>

