<script setup lang="ts">
import { computed } from "vue";
import BlockRenderer from "../blockContent/BlockRenderer.vue";

const props = defineProps<{
  page: any;
}>();

const emit = defineEmits(["action"]);

const pageStyle = computed(() => ({
  backgroundColor: props.page.styles?.backgroundColor || "transparent",
  backgroundImage: props.page.styles?.backgroundImage
    ? `url(${props.page.styles.backgroundImage})`
    : "none",
  backgroundSize: "cover",
  minHeight: "100vh",
  width: "100%",
}));
</script>

<template>
  <section class="page-renderer" :style="pageStyle">
    <BlockRenderer
      v-for="block in page.blocks"
      :key="block.id"
      :block="block"
      @action="$emit('action', $event)"
    />
  </section>
</template>
