<template>
  <div class="service-renderer" :class="`service-renderer--${layout}`">
    <ServiceCard
      v-for="svc in services"
      :key="svc._id"
      :service="svc"
      :layout="layout"
      :widgetDisplay="widgetDisplay"
      :pricingStyle="pricingStyle"
      :itemStyle="itemStyle"
      :selected="selectedServiceIds.includes(svc._id)"
      :selectionMode="selectionMode"
      :selectionRequired="selectionRequired"
      @toggle-select="handleSelect"
    />
  </div>
</template>

<script setup lang="ts">
import { computed } from "vue";
import ServiceCard from "./ServiceCard.vue";

const emit = defineEmits(["action"]);

const props = defineProps<{
  widget: any;
}>();

/* -----------------------------
STATE
----------------------------- */

const layout = computed(() => props.widget.props.layout ?? "row");
const services = computed(() => props.widget.props.services ?? []);
const widgetDisplay = computed(() => props.widget.props.widgetDisplay ?? {});
const pricingStyle = computed(() => props.widget.props.pricingStyle ?? {});
const itemStyle = computed(() => props.widget.props.itemStyle ?? {});
const selectionMode = computed(() => props.widget.props.selectionMode ?? "view");
const selectionRequired = computed(() => props.widget.props.selectionRequired ?? false);
const selectedServiceIds = computed(() => props.widget.props.selectedServiceIds ?? []);

/* -----------------------------
SELECTION LOGIC (FIXED 2026)
----------------------------- */

function handleSelect(id: string) {
  console.log("[handleSelect] clicked service id:", id);
  console.log(" selectionMode:", selectionMode.value);
  console.log(" current selectedServiceIds:", selectedServiceIds.value);

  if (selectionMode.value === "view") {
    console.log("⛔ view mode — selection blocked");
    return;
  }

  let next = [...selectedServiceIds.value];

  // SINGLE
  if (selectionMode.value === "single") {
    console.log(" single-select mode");

    if (next.includes(id)) {
      console.log("🔁 already selected → clearing selection");
      next = [];
    } else {
      console.log("➕ selecting only this item");
      next = [id];
    }
  }

  // MULTIPLE
  else {
    console.log(" multiple-select mode");

    if (next.includes(id)) {
      console.log("➖ removing from selection");
      next = next.filter((x) => x !== id);
    } else {
      console.log("➕ adding to selection");
      next = [...next, id];
    }
  }

  console.log("final selection:", next);

  props.widget.props.selectedServiceIds = next;

  emit("action", {
    type: "service-select",
    selectedServiceIds: next,
  });
}
</script>

