<template>
  <div class="app-container">
    <div class="app-shell">
      <div class="fu-topbar">
        <div class="fu-topbar-l">
          <button class="fu-menu-toggle" @click="toggleMenu">
            <!-- Menu Icon -->
            <svg
              width="24"
              height="24"
              viewBox="0 0 24 24"
              fill="none"
              xmlns="http://www.w3.org/2000/svg"
            >
              <path
                d="M21 3.30758C22.6569 3.30758 24 4.65072 24 6.30758V20.9939C24 22.6507 22.6569 23.9939 21 23.9939H11.4534C11.4356 23.9939 11.4213 23.9795 11.4213 23.9618C11.4213 23.9454 11.4337 23.9317 11.45 23.9298C16.2789 23.3868 20.0467 19.2815 20.0467 14.3086C20.0467 11.336 18.7127 8.57663 16.3919 6.72481C16.1055 6.49913 15.6906 6.54739 15.4636 6.83277L14.2226 8.39329C13.9975 8.67631 14.0441 9.08814 14.3268 9.31371C15.8619 10.532 16.739 12.3533 16.739 14.3086C16.739 17.4578 14.4366 20.0893 11.4213 20.5949C11.0742 20.6559 10.7208 20.6863 10.3554 20.6863H3C1.34315 20.6863 0 19.3431 0 17.6863V3C0 1.34315 1.34315 3.14256e-06 3 3.14256e-06H11.2752C11.3559 3.14256e-06 11.4213 0.0654245 11.4213 0.146126C11.4213 0.213947 11.3744 0.272792 11.3085 0.289108C7.08918 1.33486 3.95326 5.15701 3.95326 9.69139C3.95326 12.6578 5.28734 15.4234 7.61423 17.2691C7.89608 17.4972 8.30985 17.4518 8.53555 17.168L9.77497 15.6096C10.0018 15.3243 9.95638 14.9095 9.67311 14.6802C8.14413 13.4619 7.26097 11.6467 7.26097 9.69139C7.26097 6.95026 8.99086 4.6111 11.4213 3.70954C12.1157 3.44765 12.8649 3.30758 13.6446 3.30758H21Z"
                fill="#FFD37B"
              />
            </svg>
          </button>

          <slot name="brand-logo"> </slot>
        </div>
        <div class="fu-topbar-c">
          <slot name="header" />
        </div>

        <div class="fu-topbar-r">
          <!-- <FusionButton  variant="ghost" @click="toggleAiPanel">
           Ai 
            </FusionButton> -->

          <slot name="header-right" />
        </div>
      </div>

      <!-- BODY AREA (with AI inside) -->
      <div class="fu-main-area">
        <div class="fu-nav-panel" :class="{ open: isMenuOpen }">
          <section class="fu-sidebar">
            <slot name="modules-sidebar" />
          </section>

          <section class="fu-menu" v-show="isInnerMenuVisible">
            <slot name="module-menu" />
          </section>
        </div>

        <!-- Body slot + AI Panel wrapper -->
        <div class="fu-body-area" :class="{ 'ai-open': isAiOpen }">
          <div @click="closeMenuOnMobile" class="fu-body-slot">
            <slot />
          </div>

          <!-- AI PANEL (inside body area) -->
          <transition name="slide-left">
            <div v-if="isAiOpen" class="ai-panel" :style="{ width: aiWidth + 'px' }">
              <div class="ai-resize-handle" @mousedown="startResizing"></div>

              <div class="ai-panel-body">
                <header>
                  <h3>Àdisa</h3>
                  <div class="ai-header-actions">
                    <FusionActionButton
                      :icon="isMaximized ? Minimize2 : Maximize2"
                      variant="ghost"
                      size="sm"
                      @click="toggleMaximize"
                    />
                    <FusionActionButton
                      :icon="X"
                      variant="ghost"
                      size="sm"
                      @click="toggleAiPanel"
                    />
                  </div>
                </header>

                <!-- Scrollable region (body) -->
                <div class="ai-content">
                  <slot name="ai-content" />
                </div>
              </div>
            </div>
          </transition>
        </div>
      </div>
    </div>

    <FusionModal
      v-if="showMobileAiModal"
      :isVisible="showMobileAiModal"
      title="Adisa"
      size="sm"
      @close="showMobileAiModal = false"
      @cancel="showMobileAiModal = false"
    >
      Downlaod Skkido to use Adisa on Mobile
    </FusionModal>
  </div>
</template>

<script setup>
import { ref, onMounted, onBeforeUnmount, nextTick } from "vue";
import { X, Minimize2, Maximize2 } from "lucide-vue-next";
import FusionModal from "@/components/modal/FusionModal.vue";

const isMenuOpen = ref(false);
const isInnerMenuVisible = ref(true);
const isAiOpen = ref(false);
const aiWidth = ref(340);
const isMaximized = ref(false);
const windowWidth = ref(typeof window !== "undefined" ? window.innerWidth : 1200);

const BREAKPOINT = 991;
let isResizing = false;
const STORAGE_KEY = "fu-app-ai-panel";

const showMobileAiModal = ref(false); //  new modal state

const props = defineProps({
  listenToToggleEvent: { type: Boolean, default: true },
});

/* Sidebar toggle */
function toggleMenu() {
  if (windowWidth.value <= BREAKPOINT) {
    isMenuOpen.value = !isMenuOpen.value;
    isInnerMenuVisible.value = true;
  } else {
    isInnerMenuVisible.value = !isInnerMenuVisible.value;
  }
}

/* AI toggle — unified for desktop & mobile */
function toggleAiPanel() {
  if (windowWidth.value <= BREAKPOINT) {
    //  On mobile → show modal instead of sidebar AI
    showMobileAiModal.value = true;
    isAiOpen.value = false;
    persistState();
    return;
  }

  //  Desktop → toggle sidebar AI
  isAiOpen.value = !isAiOpen.value;
  persistState();

  if (isAiOpen.value) {
    window.dispatchEvent(new Event("open-ai"));
  }
}

/* Maximize toggle */
const defaultAiWidth = 340;
const maxAiWidth = 500;
function toggleMaximize() {
  aiWidth.value = isMaximized.value ? defaultAiWidth : maxAiWidth;
  isMaximized.value = !isMaximized.value;
  persistState();
}

/* --- Resize logic --- */
function startResizing(e) {
  isResizing = true;
  document.body.style.cursor = "col-resize";
  window.addEventListener("mousemove", resizePanel);
  window.addEventListener("mouseup", stopResizing);
}

function resizePanel(e) {
  if (!isResizing) return;
  const newWidth = window.innerWidth - e.clientX;
  if (newWidth > 280 && newWidth < 600) {
    aiWidth.value = newWidth;
    persistState();
  }
}

function stopResizing() {
  isResizing = false;
  document.body.style.cursor = "default";
  window.removeEventListener("mousemove", resizePanel);
  window.removeEventListener("mouseup", stopResizing);
}

/* Handle window resize */
function handleResize() {
  windowWidth.value = window.innerWidth;
}

/* Close menu on mobile */
function closeMenuOnMobile() {
  if (windowWidth.value <= BREAKPOINT && isMenuOpen.value) {
    isMenuOpen.value = false;
  }
}

/* Persistent helpers */
function persistState() {
  const data = {
    open: isAiOpen.value,
    width: aiWidth.value,
    maximized: isMaximized.value,
  };
  localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
}

function restoreState() {
  const saved = localStorage.getItem(STORAGE_KEY);
  if (!saved) return;
  try {
    const { open, width, maximized } = JSON.parse(saved);
    isAiOpen.value = !!open;
    aiWidth.value = width || defaultAiWidth;
    isMaximized.value = !!maximized;
  } catch (e) {
    console.warn("Failed to restore AI panel state:", e);
  }
}

/* --- Lifecycle --- */
onMounted(() => {
  restoreState();
  window.addEventListener("resize", handleResize);

  if (props.listenToToggleEvent) {
    window.addEventListener("toggle-ai", toggleAiPanel);
  }

  if (isAiOpen.value) {
    const handleTabsReady = () => {
      window.removeEventListener("tabs-ready", handleTabsReady);
      nextTick(() => {
        isAiOpen.value = true;
        window.dispatchEvent(new Event("open-ai"));
      });
    };
    window.addEventListener("tabs-ready", handleTabsReady);
  }
});
</script>

