<template>
  <div class="fu-action-btn-wrapper" @mouseenter="showTip" @mouseleave="hideTip">
    <button
      class="fu-action-btn"
      :class="[
        `fu-action-btn--${size}`,
        `fu-action-btn--${variant}`,
        { 'is-loading': loading },
      ]"
      :disabled="disabled || loading"
      @click="!loading ? $emit('click', $event) : null"
    >
      <span v-if="loading" class="fu-spinner"></span>
      <component v-else-if="icon" :is="icon" class="fu-action-btn__icon" :size="20" />
    </button>

    <Teleport to="body">
      <span v-if="tooltip && tipVisible" class="fu-tooltip" :style="tipStyle">{{
        tooltip
      }}</span>
    </Teleport>
  </div>
</template>

<script setup lang="ts">
import { ref, type Component } from "vue";

interface Props {
  disabled?: boolean;
  size?: "sm" | "md" | "lg";
  variant?: "solid" | "subtle" | "outline" | "ghost" | "danger";
  tooltip?: string | null;
  loading?: boolean;
  icon?: Component | null;
}

withDefaults(defineProps<Props>(), {
  disabled: false,
  size: "md",
  variant: "subtle",
  tooltip: null,
  loading: false,
  icon: null,
});

defineEmits<{ (e: "click", ev: MouseEvent): void }>();

const tipVisible = ref(false);
const tipStyle = ref({});

function showTip(e: MouseEvent) {
  const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
  tipStyle.value = {
    position: "fixed",
    left: `${rect.left + rect.width / 2}px`,
    top: `${rect.top - 8}px`,
    transform: "translateX(-50%) translateY(-100%)",
    zIndex: 99999,
  };
  tipVisible.value = true;
}

function hideTip() {
  tipVisible.value = false;
}
</script>

<style scoped lang="scss">
@use "./FusionActionButton.scss";
</style>
