<template>
  <div class="fu-dropdown" ref="dropdown">
    <div class="fu-dropdown__trigger" @click="toggleDropdown">
      <slot name="trigger"></slot>
    </div>

    <teleport to="body">
      <transition name="fade">
        <div
          v-if="dropdownOpen"
          class="fu-dropdown__menu"
          :class="[`fu-dropdown__menu--${align}`]"
          :style="menuPosition"
          ref="menuRef"
        >
          <!-- CONTENT -->
          <div v-if="content" class="content">
            <slot name="content"></slot>
          </div>

          <!-- ================= GROUP MODE ================= -->
          <template v-if="groups?.length">
            <div v-for="(group, gIndex) in groups" :key="gIndex">
              <!-- Group Label -->
              <div v-if="group.label" class="fu-dropdown__group-label">
                {{ group.label }}
              </div>

              <!-- Items -->
              <template
                v-for="(item, i) in group.actions"
                :key="
                  item.type === 'divider'
                    ? `divider-${gIndex}-${i}`
                    : `action-${item.label}-${gIndex}-${i}`
                "
              >
                <!-- DIVIDER -->
                <div v-if="item.type === 'divider'" class="fu-dropdown__divider" />

                <!-- ACTION -->
                <div v-else class="flex w-100">
                  <a
                    class="fu-dropdown__item"
                    :class="{ 'fu-dropdown__item--disabled': item.disabled }"
                    @click="!item.disabled && performClick(item)"
                  >
                    <component
                      v-if="item.icon"
                      :is="item.icon"
                      class="fu-dropdown__icon"
                    />
                    {{ item.label }}
                  </a>
                </div>
              </template>

              <!-- Divider between groups -->
              <div v-if="gIndex !== groups.length - 1" class="fu-dropdown__divider" />
            </div>
          </template>

          <!-- ================= FLAT MODE ================= -->
          <template v-else>
            <template
              v-for="(item, i) in actions"
              :key="
                item.type === 'divider' ? `divider-${i}` : `action-${item.label}-${i}`
              "
            >
              <!-- DIVIDER -->
              <div v-if="item.type === 'divider'" class="fu-dropdown__divider" />

              <!-- ACTION -->
              <div v-else class="flex w-100">
                <a
                  class="fu-dropdown__item"
                  :class="{ 'fu-dropdown__item--disabled': item.disabled }"
                  @click="!item.disabled && performClick(item)"
                >
                  <component v-if="item.icon" :is="item.icon" class="fu-dropdown__icon" />
                  {{ item.label }}
                </a>
              </div>
            </template>
          </template>
        </div>
      </transition>
    </teleport>
  </div>
</template>

<script setup lang="ts">
import { ref, onMounted, onBeforeUnmount, watch, nextTick } from "vue";
import type { Component, CSSProperties } from "vue";

/* ================= TYPES ================= */

type DropdownItem =
  | {
      type?: "action";
      label: string;
      icon?: Component;
      onClick?: () => void;
      disabled?: boolean;
    }
  | {
      type: "divider";
    };

interface ActionGroup {
  label?: string;
  actions: DropdownItem[];
}

interface Props {
  groups?: ActionGroup[];
  actions?: DropdownItem[];
  align?: "left" | "center" | "right";
  content?: boolean;
  isOpen?: boolean;
  closeOnSelect?: boolean;
}

/* ================= SETUP ================= */

const emit = defineEmits(["open", "close", "update:isOpen"]);

const props = withDefaults(defineProps<Props>(), {
  align: "right",
  content: false,
  isOpen: undefined,
  closeOnSelect: true,
});

const dropdownOpen = ref(false);
const dropdown = ref<HTMLElement | null>(null);
const menuRef = ref<HTMLElement | null>(null);

const menuPosition = ref<CSSProperties>({
  top: "0px",
  left: "0px",
});

/* ================= WATCH ================= */

watch(
  () => props.isOpen,
  (val) => {
    if (typeof val === "boolean") {
      dropdownOpen.value = val;
    }
  }
);

/* ================= METHODS ================= */

function toggleDropdown(event?: MouseEvent) {
  event?.stopPropagation();

  const willOpen = !dropdownOpen.value;

  if (willOpen) {
    document.dispatchEvent(new CustomEvent("close-all-dropdowns"));
  }

  dropdownOpen.value = willOpen;

  emit(willOpen ? "open" : "close");
  emit("update:isOpen", willOpen);

  if (willOpen) nextTick(positionMenu);
}

function positionMenu() {
  if (!dropdown.value || !menuRef.value) return;

  const rect = dropdown.value.getBoundingClientRect();
  const baseTop = rect.bottom + window.scrollY + 6;
  const menuWidth = menuRef.value.offsetWidth;

  let left = rect.left + window.scrollX;

  if (props.align === "center") {
    left += rect.width / 2 - menuWidth / 2;
  } else if (props.align === "right") {
    left = rect.right - menuWidth + window.scrollX;
  }

  menuPosition.value = {
    position: "absolute",
    top: `${baseTop}px`,
    left: `${left}px`,
    zIndex: "2000",
  };
}

function performClick(action: any, event?: MouseEvent) {
  event?.stopPropagation();

  action.onClick?.();

  if (props.closeOnSelect) {
    closeDropdown();
  }
}

function closeDropdown() {
  dropdownOpen.value = false;
  emit("close");
  emit("update:isOpen", false);
}

function handleClickOutside(event: MouseEvent) {
  if (
    dropdownOpen.value &&
    dropdown.value &&
    !dropdown.value.contains(event.target as Node) &&
    menuRef.value &&
    !menuRef.value.contains(event.target as Node)
  ) {
    closeDropdown();
  }
}

function handleResize() {
  if (dropdownOpen.value) closeDropdown();
}

function handleGlobalClose() {
  closeDropdown();
}

/* ================= LIFECYCLE ================= */

onMounted(() => {
  document.addEventListener("click", handleClickOutside);
  window.addEventListener("resize", handleResize);
  document.addEventListener("close-all-dropdowns", handleGlobalClose);
});

onBeforeUnmount(() => {
  document.removeEventListener("click", handleClickOutside);
  window.removeEventListener("resize", handleResize);
  document.removeEventListener("close-all-dropdowns", handleGlobalClose);
});
</script>

