<template>
  <div class="fcv-wrap">
    <div class="fcv-a4">
      <div class="fcv-body" v-html="renderedContent" />

      <div class="fcv-sigs">
        <div class="fcv-sigs__label">Signatures</div>
        <div class="fcv-sigs__rule" />
        <div class="fcv-sigs__grid">
          <div
            v-for="(sig, i) in localSigs"
            :key="sig.id"
            class="fcv-sig"
            :class="{
              'fcv-sig--signed': isSigned(sig),
              'fcv-sig--required': sig.required && !isSigned(sig),
              'fcv-sig--active': activeSigId === sig.id && !isSigned(sig),
              'fcv-sig--invalidated': !!sig.invalidatedOn,
            }"
          >
            <template v-if="isSigned(sig)">
              <div
                class="fcv-sig__box fcv-sig__box--done"
                :class="{ 'fcv-sig__box--void': sig.invalidatedOn }"
              >
                <img
                  v-if="sig.signatureData"
                  :src="sig.signatureData"
                  class="fcv-sig__img"
                  alt="Signature"
                />
              </div>
              <div class="fcv-sig__footer">
                <div class="fcv-sig__footer-left">
                  <span class="fcv-sig__name">{{ sig.signerName || "—" }}</span>
                  <span v-if="sig.signerRole" class="fcv-sig__role">{{
                    sig.signerRole
                  }}</span>
                  <span v-if="sig.signerCompany" class="fcv-sig__company">{{
                    sig.signerCompany
                  }}</span>
                </div>
                <div class="fcv-sig__footer-right">
                  <span class="fcv-sig__badge fcv-sig__badge--signed">✓ Signed</span>
                  <span class="fcv-sig__date">{{ fmtDate(sig.signedOn) }}</span>
                </div>
              </div>
            </template>

            <template v-else>
              <div
                v-if="activeSigId !== sig.id"
                class="fcv-sig__box fcv-sig__box--unsigned"
                @click="openSig(sig.id)"
              >
                <svg
                  class="fcv-sig__pen"
                  width="20"
                  height="20"
                  viewBox="0 0 24 24"
                  fill="none"
                  stroke="currentColor"
                  stroke-width="1.5"
                >
                  <path d="M12 20h9" />
                  <path d="M16.5 3.5a2.121 2.121 0 013 3L7 19l-4 1 1-4L16.5 3.5z" />
                </svg>
                <span class="fcv-sig__prompt">Click to sign</span>
              </div>

              <div v-else class="fcv-sigpad">
                <div class="fcv-sigpad__tabs">
                  <button
                    class="fcv-sigpad__tab"
                    :class="{ 'fcv-sigpad__tab--active': sigMode === 'type' }"
                    @click="sigMode = 'type'"
                  >
                    Type name
                  </button>
                  <button
                    class="fcv-sigpad__tab"
                    :class="{ 'fcv-sigpad__tab--active': sigMode === 'draw' }"
                    @click="sigMode = 'draw'"
                  >
                    Draw
                  </button>
                </div>

                <div v-if="sigMode === 'type'" class="fcv-sigpad__type-panel">
                  <input
                    v-model="typedName"
                    class="fcv-sigpad__name-input"
                    placeholder="Your full name"
                    @input="draft.signerName = typedName"
                  />
                  <div class="fcv-sigpad__type-preview">
                    <span class="fcv-sigpad__cursive">{{
                      typedName || "Your Signature"
                    }}</span>
                  </div>
                  <div class="fcv-sigpad__font-row">
                    <button
                      v-for="f in fontOptions"
                      :key="f.value"
                      class="fcv-sigpad__font-btn"
                      :style="{ fontFamily: f.value }"
                      @click="selectedFont = f.value"
                    >
                      Aa
                    </button>
                  </div>
                </div>

                <div v-if="sigMode === 'draw'" class="fcv-sigpad__draw-panel">
                  <FusignaturePad
                    v-model:image="drawingData"
                    class="fcv-sigpad__canvas-wrap"
                  />
                </div>

                <div class="fcv-sigpad__details">
                  <input
                    v-model="draft.signerName"
                    class="fcv-sigpad__field"
                    placeholder="Full name *"
                  />
                  <input
                    v-model="draft.signerRole"
                    class="fcv-sigpad__field"
                    placeholder="Role / title"
                  />

                  <input
                    v-model="draft.signerCompany"
                    class="fcv-sigpad__field"
                    placeholder="Company"
                  />
                </div>

                <div class="fcv-sigpad__actions">
                  <button class="fcv-sigpad__cancel" @click="closeSig">Cancel</button>
                  <button
                    class="fcv-sigpad__submit"
                    :disabled="!canSubmit"
                    @click="submitSignature(sig, i)"
                  >
                    Sign document
                  </button>
                </div>
              </div>
            </template>
