</template>

<script setup>
import { ref, computed, watch } from "vue";
import FusignaturePad from "./FuSignaturePad.vue";

// ── Rendered HTML ───
const renderedContent = computed(() => {
  if (!props.content) return "";

  const parser = new DOMParser();
  const doc = parser.parseFromString(props.content, "text/html");

  doc.querySelectorAll("span[fieldtype='smart']").forEach((el) => {
    const value = el.getAttribute("content") || "";
    el.replaceWith(value);
  });

  return doc.body.innerHTML;
});

const props = defineProps({
  widgetId: { type: [String, Number], default: null },
  content: { type: String, default: "" },
  signatures: { type: Array, default: () => [] },
});
const emit = defineEmits(["update"]);

const localSigs = ref(JSON.parse(JSON.stringify(props.signatures)));
const activeSigId = ref(null);
const sigMode = ref("type");
const typedName = ref("");
const selectedFont = ref("'Caveat', cursive");
const drawingData = ref(null); // This holds the base64 from the pad
const draft = ref({ signerName: "", signerRole: "", signerCompany: "" });

const fontOptions = [
  { label: "Caveat", value: "'Caveat', cursive" },
  { label: "Dancing", value: "'Dancing Script', cursive" },
  { label: "Pacifico", value: "'Pacifico', cursive" },
  { label: "Satisfy", value: "'Satisfy', cursive" },
];

const canSubmit = computed(() => {
  if (!draft.value.signerName.trim()) return false;
  return sigMode.value === "type" ? !!typedName.value.trim() : !!drawingData.value;
});

function openSig(id) {
  activeSigId.value = id;
  sigMode.value = "type";
  drawingData.value = null;
  typedName.value = "";
}

function closeSig() {
  activeSigId.value = null;
}

function isSigned(sig) {
  return !!sig.signedOn && !!sig.signatureData;
}

function submitSignature(sig, index) {
  let signatureData = null;
  let signatureType = sigMode.value;

  if (sigMode.value === "type") {
    // Reusing your SVG logic for typed names
    const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="320" height="80" viewBox="0 0 320 80">
      <text x="160" y="54" text-anchor="middle" font-family="${selectedFont.value}" font-size="38" fill="#111827">${typedName.value}</text>
    </svg>`;
    signatureData =
      "data:image/svg+xml;base64," + btoa(unescape(encodeURIComponent(svg)));
  } else {
    signatureData = drawingData.value;
  }

  const updated = {
    ...sig,
    ...draft.value,
    signatureType,
    signatureData,
    signedOn: new Date().toISOString(),
  };

  localSigs.value[index] = updated;
  activeSigId.value = null;

  emit("update", {
    widgetId: props.widgetId,
    signatures: JSON.parse(JSON.stringify(localSigs.value)),
    updatedSig: updated,
    sigIndex: index,
  });
}

function fmtDate(iso) {
  if (!iso) return "";

  return new Date(iso).toLocaleString("en-GB", {
    day: "numeric",
    month: "short",
    year: "numeric",
    hour: "2-digit",
    minute: "2-digit",
    hour12: false,
  });
}
</script>
