<template>
  <nav class="fu-sidebar" :style="sidebarStyle">
    <ul class="fu-sidebar__list">
      <li
        v-for="mod in modules"
        :key="mod.name"
        :class="{ active: activeModule === mod.name }"
      >
        <div
          class="fu-sidebar__item"
          :class="{ 'fu-sidebar__item--collapsed': hideLabels }"
          @click="$emit('select', mod)"
          @mouseenter="(e) => onMouseEnter(e, mod.name)"
          @mouseleave="onMouseLeave"
        >
          <div class="fu-sidebar__icon-wrapper">
            <component :is="mod.icon" class="fu-sidebar__icon" :size="20" />
            <span v-if="mod.count" class="fu-sidebar__badge">
              {{ mod.count > 99 ? "99+" : mod.count }}
            </span>
          </div>

          <span v-if="!hideLabels" class="fu-sidebar__label">{{ mod.label }}</span>
        </div>
      </li>
    </ul>

    <Teleport to="body">
      <span
        v-if="hideLabels && hoveredModule"
        class="fu-sidebar__tooltip"
        :style="tooltipStyle"
      >
        {{ hoveredModule }}
      </span>
    </Teleport>
  </nav>
</template>

<script setup lang="ts">
import { computed, ref, type Component } from "vue";

interface Module {
  name: string;
  label: string;
  icon: Component;
  count?: number;
}

const props = defineProps<{
  modules: Module[];
  activeModule?: string;
  backgroundColor?: string;
  borderRadius?: string;
  hideLabels?: boolean;
}>();

defineEmits(["select"]);

const hoveredLabel = ref<string | null>(null);
const hoveredModule = ref<string | null>(null);
const tooltipStyle = ref<Record<string, string>>({});

const sidebarStyle = computed(() => ({
  "--fu-sidebar-bg": props.backgroundColor ?? "var(--fu-brand-background)",
  "--fu-sidebar-radius": props.borderRadius ?? "0px",
  width: props.hideLabels ? "54px" : "70px",
}));

function onMouseEnter(e: MouseEvent, modName: string) {
  if (!props.hideLabels) return;
  const mod = props.modules.find(m => m.name === modName);
  hoveredModule.value = mod?.label ?? modName;
  const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
  tooltipStyle.value = {
    position: "fixed",
    left: `${rect.right + 8}px`,
    top: `${rect.top + rect.height / 2}px`,
    transform: "translateY(-50%)",
    zIndex: "99999",
  };
}

function onMouseLeave() {
  hoveredModule.value = null;
}
</script>

<style scoped lang="scss">
@use "./FusionSidebar.scss";

.fu-sidebar__item--collapsed {
  justify-content: center;
}

.fu-sidebar__tooltip {
  background: #111;
  color: #fff;
  font-size: 12px;
  padding: 4px 10px;
  border-radius: 6px;
  white-space: nowrap;
  pointer-events: none;

  &::before {
    content: "";
    position: absolute;
    right: 100%;
    top: 50%;
    transform: translateY(-50%);
    border-width: 5px;
    border-style: solid;
    border-color: transparent #111 transparent transparent;
  }
}
</style>
