<template>
  <div
    class="fu-btn-wrapper"
    :class="{ 'has-tooltip': tooltip }"
    :style="buttonWidth ? { width: buttonWidth } : {}"
    @mouseenter="showTip"
    @mouseleave="hideTip"
  >
    <component
      :is="link ? 'a' : 'button'"
      class="fu-btn"
      :class="[`fu-btn--${variant}`, `fu-btn--${size}`, { 'is-loading': loading }]"
      :href="link || undefined"
      :target="link ? target : undefined"
      :rel="link && target === '_blank' ? 'noopener noreferrer' : undefined"
      :disabled="!link && (disabled || loading)"
      @click="!link && !loading ? $emit('click', $event) : null"
      :style="buttonWidth ? { width: buttonWidth } : {}"
    >
      <span v-if="loading" class="fu-spinner"></span>
      <component v-if="icon" :is="icon" class="fu-btn-icon" :size="16" />
      <span v-if="loading">{{ loadingText || "Loading..." }}</span>
      <span v-else
        ><slot>{{ text }}</slot></span
      >
    </component>

    <Teleport to="body">
      <span v-if="tooltip && tipVisible" class="fu-btn-tooltip" :style="tipStyle">
        {{ tooltip }}
      </span>
    </Teleport>
  </div>
</template>

<script setup lang="ts">
import { ref, type Component } from "vue";

interface Props {
  text?: string;
  disabled?: boolean;
  size?: "sm" | "md" | "lg";
  variant?: "solid" | "subtle" | "outline" | "ghost" | "danger" | "success";
  tooltip?: string | null;
  loading?: boolean;
  loadingText?: string | null;
  link?: string | null;
  icon?: Component | null;
  target?: "_parent" | "_blank";
  buttonWidth?: string | null;
}

withDefaults(defineProps<Props>(), {
  text: "Click Me",
  disabled: false,
  size: "sm",
  variant: "solid",
  tooltip: null,
  loading: false,
  loadingText: null,
  link: null,
  icon: null,
  target: "_parent",
  buttonWidth: "",
});

defineEmits<{ (e: "click", ev: MouseEvent): void }>();

const tipVisible = ref(false);
const tipStyle = ref({});

function showTip(e: MouseEvent) {
  const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
  tipStyle.value = {
    position: "fixed",
    left: `${rect.left + rect.width / 2}px`,
    top: `${rect.top - 8}px`,
    transform: "translateX(-50%) translateY(-100%)",
    zIndex: "99999",
  };
  tipVisible.value = true;
}

function hideTip() {
  tipVisible.value = false;
}
</script>

<style lang="scss" scoped>
@use "./FusionButton.scss";
</style>

