import { ref, watchEffect } from "vue";

export type ThemeMode = "light" | "dark" | "auto";

const saved = (localStorage.getItem("theme") as ThemeMode) || "auto";
const theme = ref<ThemeMode>(saved);

function getSystemTheme(): "light" | "dark" {
  return window.matchMedia("(prefers-color-scheme: dark)").matches ? "dark" : "light";
}

function applyTheme(value: ThemeMode) {
  const resolved = value === "auto" ? getSystemTheme() : value;
  document.documentElement.setAttribute("data-theme", resolved);
  localStorage.setItem("theme", value);
}

// Apply immediately before anything mounts
applyTheme(saved);

// Re-apply when OS preference changes and user is on auto
window.matchMedia("(prefers-color-scheme: dark)").addEventListener("change", () => {
  if (theme.value === "auto") applyTheme("auto");
});

watchEffect(() => applyTheme(theme.value));

export function useTheme() {
  return {
    theme,
    setTheme: (mode: ThemeMode) => {
      theme.value = mode;
    },
    toggleTheme: () => {
      theme.value = theme.value === "dark" ? "light" : "dark";
    },
  };
}