<template>
  <div class="fu-video-widget" :style="wrapperStyle">
    <!-- Empty state -->
    <div v-if="!embedUrl" class="fu-empty-state">
      <VideoIcon :size="28" />
      <span>No video available</span>
    </div>

    <!-- Video -->
    <div v-else class="fu-video-frame" :style="frameStyle">
      <iframe
        :src="embedUrl"
        frameborder="0"
        allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; fullscreen"
        allowfullscreen
      />
    </div>
  </div>
</template>

<script setup lang="ts">
import { computed } from "vue";
import { VideoIcon } from "lucide-vue-next";

/* ─────────────────────────────
   Props (pure render config)
───────────────────────────── */
type ContentWidth = "sm" | "md" | "lg" | "full";

const props = defineProps<{
  src?: string;
  aspectRatio?: string;
  contentWidth?: ContentWidth;
  borderRadius?: number;
  backgroundColor?: string;
}>();

/* ─────────────────────────────
   Embed URL resolver
───────────────────────────── */
const embedUrl = computed<string>(() => {
  if (!props.src) return "";

  let url = props.src.trim();

  if (!/^https?:\/\//.test(url)) {
    url = "https://" + url;
  }

  // YouTube short link
  if (url.includes("youtu.be/")) {
    const id = url.split("youtu.be/")[1]?.split("?")[0];
    return `https://www.youtube.com/embed/${id}`;
  }

  // YouTube long form
  if (url.includes("youtube.com/watch?v=")) {
    const id = new URL(url).searchParams.get("v");
    return `https://www.youtube.com/embed/${id}`;
  }

  // Vimeo
  if (url.includes("vimeo.com/")) {
    const id = url.split("vimeo.com/")[1]?.split("?")[0];
    return `https://player.vimeo.com/video/${id}`;
  }

  // Loom
  if (url.includes("loom.com/share/")) {
    const id = url.split("loom.com/share/")[1]?.split("?")[0];
    return `https://www.loom.com/embed/${id}`;
  }

  return url;
});

/* ─────────────────────────────
   Layout styling (pure JSON style output)
───────────────────────────── */
const wrapperStyle = computed<Record<string, string>>(() => ({
  backgroundColor: embedUrl.value ? "transparent" : props.backgroundColor || "#f5f7ff",
  borderRadius: `${props.borderRadius ?? 8}px`,
  border: "1px solid #e5e7eb",
  width:
    props.contentWidth === "sm"
      ? "60%"
      : props.contentWidth === "md"
      ? "80%"
      : props.contentWidth === "lg"
      ? "100%"
      : "100%",
  margin: "0 auto",
  overflow: "hidden",
}));

/* ─────────────────────────────
   Aspect ratio calculator
───────────────────────────── */
const frameStyle = computed<Record<string, string>>(() => {
  const ratio = props.aspectRatio || "16:9";
  const [w, h] = ratio.split(":").map(Number);

  const paddingTop = w && h ? (h / w) * 100 : 56.25;

  return {
    position: "relative",
    width: "100%",
    paddingTop: `${paddingTop}%`,
  };
});
</script>
<style scoped>
.fu-video-widget {
  position: relative;
}

/* Empty state */
.fu-empty-state {
  display: flex;
  flex-direction: column;
  gap: 6px;
  align-items: center;
  justify-content: center;
  padding: 32px;
  font-size: 13px;
  color: #6b7280;
}

/* Frame system */
.fu-video-frame iframe {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  border: none;
}
</style>
