<template>
  <div class="fu-input-wrapper" :style="{ width: formWrapperWidth }">
    <!-- Label -->
    <label v-if="label" class="fu-input-label">
      {{ label }}
      <span v-if="required" class="fu-input-required">*</span>
    </label>

    <div
      class="fu-code-container"
      :class="[`fu-input--${size}`, `fu-input--${variant}`, { 'fu-input--error': error }]"
    >
      <input
        v-for="(digit, index) in codeDigits"
        :key="index"
        :ref="el => (inputs[index] = el as HTMLInputElement)"
        type="text"
        maxlength="1"
        inputmode="numeric"
        pattern="[0-9]*"
        class="fu-code-box fu-input-container"
        v-model="codeDigits[index]"
        @input="onInput(index, $event)"
        @keydown.backspace="onBackspace(index)"
        @paste="onPaste"
        :disabled="disabled"
      />
    </div>

    <!-- Error message -->
    <span v-if="error" class="fu-input-error">{{ error }}</span>
  </div>
</template>

<script setup lang="ts">
import { ref, watch, nextTick } from "vue";

interface Props {
  modelValue?: string;
  label?: string;
  length?: number;
  size?: "sm" | "md" | "lg";
  variant?: "outline" | "subtle" | "plain";
  disabled?: boolean;
  error?: string | null;
  required?: boolean;
  formWrapperWidth?: string;
}

const props = withDefaults(defineProps<Props>(), {
  modelValue: "",
  label: "",
  length: 6,
  size: "md",
  variant: "outline",
  disabled: false,
  error: null,
  required: false,
  formWrapperWidth: "fit-content",
});

const emit = defineEmits<{
  (e: "update:modelValue", value: string): void;
}>();

// Internal digits
const codeDigits = ref<string[]>(Array(props.length).fill(""));

// Track input DOM nodes
const inputs = ref<HTMLInputElement[]>([]);

/* -----------------------------
   SYNC: parent → component
-------------------------------- */
watch(
  () => props.modelValue,
  (val) => {
    if (!val) {
      codeDigits.value = Array(props.length).fill("");
      return;
    }

    const arr = val.split("").slice(0, props.length);

    while (arr.length < props.length) arr.push("");

    codeDigits.value = arr;
  },
  { immediate: true }
);

/* -----------------------------
   SYNC: component → parent
-------------------------------- */
watch(
  codeDigits,
  () => {
    emit("update:modelValue", codeDigits.value.join(""));
  },
  { deep: true }
);

/* -----------------------------
   Input Handling
-------------------------------- */
function onInput(index: number, e: Event) {
  const el = e.target as HTMLInputElement;
  const value = el.value.replace(/\D/g, "");

  codeDigits.value[index] = value;

  if (value && index < props.length - 1) {
    nextTick(() => inputs.value[index + 1]?.focus());
  }
}

function onBackspace(index: number) {
  if (!codeDigits.value[index] && index > 0) {
    nextTick(() => inputs.value[index - 1]?.focus());
  }
}

/* -----------------------------
   Pasting full OTP
-------------------------------- */
function onPaste(e: ClipboardEvent) {
  e.preventDefault();

  const pasted = e.clipboardData?.getData("text") || "";
  const digits = pasted.replace(/\D/g, "").slice(0, props.length).split("");

  if (digits.length === 0) return;

  // Fill digits into boxes
  digits.forEach((d, i) => {
    codeDigits.value[i] = d;
  });

  // Clear remaining boxes
  for (let i = digits.length; i < props.length; i++) {
    codeDigits.value[i] = "";
  }

  nextTick(() => {
    const lastIndex = Math.min(digits.length - 1, props.length - 1);
    inputs.value[lastIndex]?.focus();
  });
}
</script>

