<template>
  <div
    class="fu-date-picker fu-date-picker--plain"
    :style="{ width: formWrapperWidth, fontSize: fontSize }"
  >
    <div class="fu-date-picker" :style="{ width: formWrapperWidth }">
      <!-- Header -->
      <div class="calendar-header">
        <button @click="toggleView">
          <template v-if="viewMode === 'days'">{{
            currentMonth.format("MMMM YYYY")
          }}</template>
          <template v-else-if="viewMode === 'months'">{{ currentMonth.year() }}</template>
          <template v-else>{{ yearRangeStart }} - {{ yearRangeEnd }}</template>
        </button>
        <div class="flex flex--gap-sm">
          <button @click="prevAction">
            <ChevronLeft :size="16" color="var(--fu-color-text)" />
          </button>
          <button @click="nextAction"><ChevronRight :size="16" /></button>
        </div>
      </div>

      <!-- Days -->
      <div v-if="viewMode === 'days'">
        <div class="calendar-weekdays">
          <div v-for="d in weekdays" :key="d" class="calendar-weekday">{{ d }}</div>
        </div>
        <div class="calendar-days">
          <div
            v-for="day in daysInCalendar"
            :key="day.date.toString()"
            class="calendar-day"
            :class="{
              'calendar-day--other-month': !day.isCurrentMonth,
              'calendar-day--selected': isSelected(day.date),
              'calendar-day--disabled': isDisabled(day.date),
            }"
            @click="selectDate(day.date)"
          >
            {{ day.date.date() }}
          </div>
        </div>
      </div>

      <!-- Months -->
      <div v-else-if="viewMode === 'months'" class="calendar-months">
        <div
          v-for="(m, i) in months"
          :key="m"
          class="calendar-month"
          :class="{ 'calendar-month--selected': i === currentMonth.month() }"
          @click="selectMonth(i)"
        >
          {{ m }}
        </div>
      </div>

      <!-- Years -->
      <div v-else class="calendar-years">
        <div
          v-for="year in yearsRange"
          :key="year"
          class="calendar-year"
          :class="{ 'calendar-year--selected': year === currentMonth.year() }"
          @click="selectYear(year)"
        >
          {{ year }}
        </div>
      </div>

      <!-- Multi-select summary -->
      <div v-if="mode === 'multi' && selectedDates.length" class="calendar-multi-summary">
        <span
          >{{ selectedDates.length }} date{{
            selectedDates.length > 1 ? "s" : ""
          }}
          selected</span
        >
        <button class="calendar-multi-clear" @click="clearAll">Clear all</button>
      </div>

      <!-- Time Picker -->
      <div v-if="variant === 'date-time'" class="calendar-time">
        <FusionTextInput
          type="text"
          v-model="timeValue"
          placeholder="HH:mm or 4:30pm"
          @focus="timeOpen = true"
          @keydown.enter.prevent="applyTypedTime"
          formWrapperWidth="100%"
        >
          <template #right><ChevronDown /></template>
        </FusionTextInput>
        <div v-if="timeOpen" class="fu-time-dropdown customScrollBar">
          <div
            v-for="opt in filteredTimeOptions"
            :key="opt"
            class="fu-time-option"
            @mousedown.prevent="selectTime(opt)"
          >
            {{ opt }}
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script setup>
import { ref, computed, watch } from "vue";
import dayjs from "dayjs";
import FusionTextInput from "@/components/TextInput/FusionTextInput.vue";
import { ChevronLeft, ChevronRight, ChevronDown } from "lucide-vue-next";

const props = defineProps({
  modelValue: [String, Array],
  mode: { type: String, default: "single" },
  variant: { type: String, default: "date" },
  formWrapperWidth: String,
  fontSize: { type: String, default: "0.625rem" },
  disabledDates: { type: Array, default: () => [] }, // ← array of "YYYY-MM-DD"
});

const emit = defineEmits(["update:modelValue"]);

// ─── State ────────────────────────────────────────────────────
const currentMonth = ref(dayjs().startOf("month"));
const viewMode = ref("days");
const timeValue = ref("00:00");
const timeOpen = ref(false);

const selectedDate = ref(null);
const selectedDates = ref([]);

// ─── Weekdays / Months ────────────────────────────────────────
const weekdays = ["Su", "Mo", "Tu", "We", "Th", "Fr", "Sa"];
const months = [
  "Jan",
  "Feb",
  "Mar",
  "Apr",
  "May",
  "Jun",
  "Jul",
  "Aug",
  "Sep",
  "Oct",
  "Nov",
  "Dec",
];

// ─── Year pagination ──────────────────────────────────────────
const yearsPerPage = 12;
const yearRangeStart = computed(
  () => Math.floor(currentMonth.value.year() / yearsPerPage) * yearsPerPage
);
const yearRangeEnd = computed(() => yearRangeStart.value + yearsPerPage - 1);
const yearsRange = computed(() =>
  Array.from({ length: yearsPerPage }, (_, i) => yearRangeStart.value + i)
);

// ─── Calendar days ────────────────────────────────────────────
const daysInCalendar = computed(() => {
  const start = currentMonth.value.startOf("month").startOf("week");
  const end = currentMonth.value.endOf("month").endOf("week");
  const days = [];
  let d = start.clone();
  while (d.isBefore(end) || d.isSame(end, "day")) {
    days.push({
      date: d.clone(),
      isCurrentMonth: d.month() === currentMonth.value.month(),
    });
    d = d.add(1, "day");
  }
  return days;
});

// ─── Time options ─────────────────────────────────────────────
const timeOptions = computed(() => {
  const list = [];
  for (let h = 0; h < 24; h++)
    for (let m = 0; m < 60; m += 15)
      list.push(dayjs().hour(h).minute(m).format("h:mm A"));
  return list;
});
const filteredTimeOptions = computed(() => timeOptions.value);

// ─── Helpers ──────────────────────────────────────────────────
const isDisabled = (date) => props.disabledDates.includes(date.format("YYYY-MM-DD"));

function isSelected(date) {
  if (props.mode === "multi") {
    return selectedDates.value.includes(date.format("YYYY-MM-DD"));
  }
  return selectedDate.value && date.isSame(selectedDate.value, "day");
}

// ─── Select date ──────────────────────────────────────────────
function selectDate(date) {
  if (isDisabled(date)) return; // ← blocked if already overridden

  if (props.mode === "multi") {
    const key = date.format("YYYY-MM-DD");
    const idx = selectedDates.value.indexOf(key);
    if (idx === -1) {
      selectedDates.value = [...selectedDates.value, key];
    } else {
      selectedDates.value = selectedDates.value.filter((d) => d !== key);
    }
    selectedDates.value = [...selectedDates.value].sort();
    emit("update:modelValue", [...selectedDates.value]);
  } else {
    selectedDate.value = date.clone();
    if (props.variant === "date-time") {
      const combined = dayjs(
        `${selectedDate.value.format("YYYY-MM-DD")} ${timeValue.value}`,
        "YYYY-MM-DD HH:mm"
      );
      emit("update:modelValue", combined.format("YYYY-MM-DDTHH:mm"));
    } else {
      emit("update:modelValue", selectedDate.value.format("YYYY-MM-DD"));
    }
  }
}

function clearAll() {
  selectedDates.value = [];
  emit("update:modelValue", []);
}

// ─── Navigation ───────────────────────────────────────────────
const prevAction = () => (currentMonth.value = currentMonth.value.subtract(1, "month"));
const nextAction = () => (currentMonth.value = currentMonth.value.add(1, "month"));
const toggleView = () =>
  (viewMode.value =
    viewMode.value === "days"
      ? "months"
      : viewMode.value === "months"
      ? "years"
      : "days");
const selectMonth = (i) => {
  currentMonth.value = currentMonth.value.month(i);
  viewMode.value = "days";
};
const selectYear = (y) => {
  currentMonth.value = currentMonth.value.year(y);
  viewMode.value = "months";
};

// ─── Time handlers ────────────────────────────────────────────
function applyTypedTime() {
  if (!selectedDate.value) return;
  const parsed = dayjs(`${selectedDate.value.format("YYYY-MM-DD")} ${timeValue.value}`, [
    "YYYY-MM-DD HH:mm",
    "YYYY-MM-DD h:mm A",
  ]);
  if (parsed.isValid()) {
    timeValue.value = parsed.format("HH:mm");
    emit("update:modelValue", parsed.format("YYYY-MM-DDTHH:mm"));
    timeOpen.value = false;
  }
}

function selectTime(val) {
  if (!selectedDate.value) return;
  timeValue.value = dayjs(val, "h:mm A").format("HH:mm");
  const combined = dayjs(
    `${selectedDate.value.format("YYYY-MM-DD")} ${timeValue.value}`,
    "YYYY-MM-DD HH:mm"
  );
  emit("update:modelValue", combined.format("YYYY-MM-DDTHH:mm"));
  timeOpen.value = false;
}

// ─── Sync external modelValue ─────────────────────────────────
watch(
  () => props.modelValue,
  (val) => {
    if (props.mode === "multi") {
      selectedDates.value = Array.isArray(val) ? [...val] : [];
    } else {
      if (!val) {
        selectedDate.value = null;
        return;
      }
      const parsed = dayjs(val);
      if (parsed.isValid()) {
        selectedDate.value = parsed;
        currentMonth.value = parsed.startOf("month");
        if (props.variant === "date-time") timeValue.value = parsed.format("HH:mm");
      }
    }
  },
  { immediate: true }
);
</script>

