<template>
  <div class="fu-time-picker" ref="inputRef">
    <FusionTextInput
      type="text"
      v-model="displayValue"
      :placeholder="displayFormat === '12' ? 'hh:mm am/pm' : 'HH:mm'"
      @focus="onFocus"
      @input="onTimeInput"
      @keydown.enter.prevent="applyTypedTime"
      @blur="onTimeBlur"
      :label="label"
      :error="error"
      :required="required"
      :disabled="disabled"
      :size="size"
      :formWrapperWidth="formWrapperWidth"
    >
      <template #right>
        <ChevronDown style="cursor: pointer" @mousedown.prevent="onChevronClick" />
      </template>
    </FusionTextInput>
    <Teleport to="body">
      <div
        v-if="timeOpen"
        ref="dropdownRef"
        class="fu-time-dropdown customScrollBar"
        :class="{ 'open-up': openUpwards }"
        :style="{
          left: inputRect.left + 'px',
          width: inputRect.width + 'px',
          top: openUpwards
            ? inputRect.top - dropdownHeight + 'px'
            : inputRect.bottom + 'px',
        }"
      >
        <div
          v-for="(opt, index) in visibleTimeOptions"
          :key="opt.value"
          class="fu-time-option"
          :ref="(el) => setFirstVisible(el, index)"
          @mousedown.prevent="selectTime(opt.value)"
        >
          {{ opt.label }}
        </div>
      </div>
    </Teleport>
  </div>
</template>

<script setup>
import { ref, computed, onMounted, onBeforeUnmount, watch, nextTick } from "vue";
import FusionTextInput from "@/components/TextInput/FusionTextInput.vue";
import { ChevronDown } from "lucide-vue-next";

const props = defineProps({
  modelValue: String,
  displayFormat: {
    type: String,
    default: "12",
    validator: (v) => ["12", "24"].includes(v),
  },
  interval: { type: Number, default: 30 },
  error: String,
  label: String,
  required: Boolean,
  disabled: Boolean,
  size: String,
  formWrapperWidth: String,
});

const emit = defineEmits(["update:modelValue", "change"]);

const displayValue = ref("");
const internalValue = ref(props.modelValue || "");
const filterQuery = ref("");

const timeOpen = ref(false);
const openUpwards = ref(false);
const inputRef = ref(null);
const dropdownRef = ref(null);
const inputRect = ref({ left: 0, top: 0, bottom: 0, width: 0 });
const dropdownHeight = 240;
const firstVisibleOption = ref(null);

/* ─────────────────── Format helpers ─────────────────── */

const toDisplay = (hhmm) => {
  if (!hhmm || !/^\d{2}:\d{2}$/.test(hhmm)) return hhmm || "";
  const [h, m] = hhmm.split(":").map(Number);
  if (props.displayFormat === "24") {
    return `${String(h).padStart(2, "0")}:${String(m).padStart(2, "0")}`;
  }
  const meridian = h < 12 ? "am" : "pm";
  const hour12 = h % 12 || 12;
  return `${String(hour12).padStart(2, "0")}:${String(m).padStart(2, "0")} ${meridian}`;
};

const parseToHHMM = (raw) => {
  if (!raw) return null;
  const s = raw.trim().toLowerCase();

  if (props.displayFormat === "24") {
    const match = s.match(/^(\d{1,2}):(\d{2})$/);
    if (!match) return null;
    const h = parseInt(match[1], 10);
    const min = parseInt(match[2], 10);
    if (h > 23 || min > 59) return null;
    return `${String(h).padStart(2, "0")}:${String(min).padStart(2, "0")}`;
  }

  const match = s.match(/^(\d{1,2})(?::(\d{2}))?\s*(am|pm)$/);
  if (!match) return null;
  let h = parseInt(match[1], 10);
  const min = parseInt(match[2] || "00", 10);
  const mer = match[3];
  if (h < 1 || h > 12 || min > 59) return null;
  if (mer === "pm" && h !== 12) h += 12;
  if (mer === "am" && h === 12) h = 0;
  return `${String(h).padStart(2, "0")}:${String(min).padStart(2, "0")}`;
};

/* ─────────────────── Sync display ↔ model ─────────────────── */

displayValue.value = toDisplay(props.modelValue);

watch(
  () => props.modelValue,
  (v) => {
    internalValue.value = v || "";
    if (document.activeElement !== inputRef.value?.querySelector("input")) {
      displayValue.value = toDisplay(v);
    }
  }
);

watch(
  () => props.displayFormat,
  () => {
    displayValue.value = toDisplay(internalValue.value);
  }
);

/* ─────────────────── Time options ─────────────────── */

const timeOptions = computed(() => {
  const fmt = props.displayFormat; // explicit dep so computed re-runs on format change
  const opts = [];
  for (let h = 0; h < 24; h++) {
    for (let m = 0; m < 60; m += props.interval) {
      const hhmm = `${String(h).padStart(2, "0")}:${String(m).padStart(2, "0")}`;
      opts.push({ label: toDisplay(hhmm), value: hhmm });
    }
  }
  return opts;
});

const filteredTimeOptions = computed(() =>
  filterQuery.value
    ? timeOptions.value.filter((t) =>
        t.label.toLowerCase().includes(filterQuery.value.toLowerCase())
      )
    : timeOptions.value
);

const visibleTimeOptions = computed(() =>
  filteredTimeOptions.value.length ? filteredTimeOptions.value : timeOptions.value
);

/* ─────────────────── Input sanitisation ─────────────────── */

const onTimeInput = (e) => {
  const input = e.target;
  let val = input.value;

  if (props.displayFormat === "24") {
    val = val.replace(/[^0-9:]/g, "").slice(0, 5);

    if (/^\d{2}$/.test(val)) {
      val += ":";
      displayValue.value = val;
      filterQuery.value = val;
      nextTick(() => input.setSelectionRange(3, 3));
      return;
    }

    if (/^\d{2}:\d/.test(val)) {
      const h = parseInt(val.slice(0, 2), 10);
      if (h > 23) val = "23:" + val.slice(3);
    }

    if (/^\d{2}:\d{2}$/.test(val)) {
      const min = parseInt(val.slice(3), 10);
      if (min > 59) val = val.slice(0, 3) + "59";
    }
  } else {
    val = val.replace(/[^0-9: apm]/g, "");
    val = val
      .replace(/([ap])m*([ap])/g, "$1")
      .replace(/(am|pm).+/, "$1")
      .slice(0, 8);

    if (/^\d{2}$/.test(val)) {
      val += ":";
      displayValue.value = val;
      filterQuery.value = val;
      nextTick(() => input.setSelectionRange(3, 3));
      return;
    }

    if (/^\d{2}/.test(val)) {
      const h = parseInt(val.slice(0, 2), 10);
      if (h > 12) val = "12" + val.slice(2);
      if (h === 0) val = "01" + val.slice(2);
    }

    if (/^\d{2}:\d{2}/.test(val)) {
      const min = parseInt(val.slice(3, 5), 10);
      if (min > 59) val = val.slice(0, 3) + "59" + val.slice(5);
    }
  }

  displayValue.value = val;
  filterQuery.value = val;
};

/* ─────────────────── Apply / commit ─────────────────── */

const applyTypedTime = () => {
  const hhmm = parseToHHMM(displayValue.value);
  if (!hhmm) {
    displayValue.value = toDisplay(internalValue.value);
    filterQuery.value = "";
    timeOpen.value = false;
    return;
  }
  internalValue.value = hhmm;
  displayValue.value = toDisplay(hhmm);
  filterQuery.value = "";
  emit("update:modelValue", hhmm);
  emit("change", hhmm);
  timeOpen.value = false;
};

/* ─────────────────── Dropdown ─────────────────── */

const calculatePosition = () => {
  if (!inputRef.value) return;
  const rect = inputRef.value.getBoundingClientRect();
  inputRect.value = {
    left: rect.left,
    top: rect.top,
    bottom: rect.bottom,
    width: rect.width,
  };
  const spaceBelow = window.innerHeight - rect.bottom;
  openUpwards.value = spaceBelow < dropdownHeight && rect.top > spaceBelow;
};

const setFirstVisible = (el, index) => {
  if (index === 0 && el) firstVisibleOption.value = el;
};

const selectTime = (hhmm) => {
  internalValue.value = hhmm;
  displayValue.value = toDisplay(hhmm);
  filterQuery.value = "";
  emit("update:modelValue", hhmm);
  emit("change", hhmm);
  timeOpen.value = false;
};

const onFocus = () => {
  displayValue.value = toDisplay(internalValue.value);
  filterQuery.value = "";
  timeOpen.value = true;
  calculatePosition();
};

const onTimeBlur = () =>
  setTimeout(() => {
    applyTypedTime();
    timeOpen.value = false;
  }, 120);

const onClickOutside = (e) => {
  if (
    inputRef.value &&
    !inputRef.value.contains(e.target) &&
    dropdownRef.value &&
    !dropdownRef.value.contains(e.target)
  ) {
    timeOpen.value = false;
  }
};

/* ─────────────────── Scroll to first visible ─────────────────── */

watch(filterQuery, async () => {
  await nextTick();
  if (firstVisibleOption.value)
    firstVisibleOption.value.scrollIntoView({ behavior: "smooth", block: "nearest" });
});

/* ─────────────────── Lifecycle ─────────────────── */

const onResize = () => calculatePosition();
onMounted(() => {
  window.addEventListener("resize", onResize);
  document.addEventListener("mousedown", onClickOutside);
  nextTick(calculatePosition);
});
onBeforeUnmount(() => {
  window.removeEventListener("resize", onResize);
  document.removeEventListener("mousedown", onClickOutside);
});

const onChevronClick = () => {
  if (props.disabled) return;
  if (timeOpen.value) {
    timeOpen.value = false;
  } else {
    displayValue.value = toDisplay(internalValue.value);
    filterQuery.value = "";
    timeOpen.value = true;
    calculatePosition();
  }
};
</script>

<style scoped lang="scss">
.fu-time-dropdown {
  position: fixed;
  max-width: 180px;
  max-height: 240px;
  overflow-y: auto;
  background: var(--fu-content-body);
  color: var(--fu-color-text);
  border: 0.5px solid var(--fu-border);
  border-radius: 4px;
  z-index: 9999;
  box-shadow: 0 -6px 12px rgba(0, 0, 0, 0.15);
}

.fu-time-option {
  padding: 8px 12px;
  cursor: pointer;
  user-select: none;

  &:hover {
    background: var(--fu-surface-hover);
    color: var(--fu-color-text);
  }
}
</style>
