<template>
  <div class="fu-pagination">
    <!-- Left side -->
    <div class="fu-pagination__left">
      <div v-if="showInfo" class="fu-pagination__info">
        <div v-if="loading" class="fu-skeleton-cell fu-skeleton-cell--info" />
        <template v-else>{{ start }}–{{ end }} of {{ total }}</template>
      </div>

      <FusionStatusDropdown
        v-if="showPageSize"
        v-model="pageSizeModel"
        :options="pageSizeDropdownOptions"
        align="left"
        size="sm"
        :disabled="loading"
      />
    </div>

    <!-- Right side -->
    <div class="fu-pagination__controls">
      <!-- Previous -->
      <button
        class="fu-pagination__btn"
        :disabled="page <= 1 || loading"
        @click="goTo(page - 1)"
        aria-label="Previous page"
      >
        <ChevronLeft class="fu-pagination__icon" />
      </button>

      <!-- Skeleton page buttons -->
      <template v-if="loading">
        <div
          v-for="i in 5"
          :key="`skel-${i}`"
          class="fu-skeleton-cell fu-skeleton-cell--page"
        />
      </template>

      <!-- Real page numbers -->
      <template v-else-if="variant !== 'simple'">
        <button
          v-for="p in pages"
          :key="p.key"
          class="fu-pagination__btn"
          :class="{ active: p.page === page, ellipsis: p.ellipsis }"
          :disabled="!!p.ellipsis"
          @click="handlePageClick(p.page)"
        >
          {{ p.label }}
        </button>
      </template>

      <!-- Next -->
      <button
        class="fu-pagination__btn"
        :disabled="page >= totalPages || loading"
        @click="goTo(page + 1)"
        aria-label="Next page"
      >
        <ChevronRight class="fu-pagination__icon" />
      </button>
    </div>
  </div>
</template>

<script setup lang="ts">
import { computed } from "vue";
import { ChevronLeft, ChevronRight } from "lucide-vue-next";
import FusionStatusDropdown from "@/components/StatusDropdown/FusionStatusDropdown.vue";

interface PageSizeOption {
  label: string;
  value: number;
}

interface Props {
  page: number;
  pageSize: number;
  total: number;
  variant?: "default" | "simple";
  showInfo?: boolean;
  siblingCount?: number;
  showPageSize?: boolean;
  pageSizeOptions?: number[];
  loading?: boolean;
}

const props = withDefaults(defineProps<Props>(), {
  variant: "default",
  showInfo: true,
  siblingCount: 1,
  showPageSize: true,
  pageSizeOptions: () => [10, 25, 50, 100],
  loading: false,
});

const emit = defineEmits<{
  (e: "update:page", page: number): void;
  (e: "update:pageSize", size: number): void;
}>();

/* -----------------------------
   Page size dropdown mapping
------------------------------ */
const pageSizeDropdownOptions = computed<PageSizeOption[]>(() =>
  props.pageSizeOptions.map((size) => ({ label: String(size), value: size }))
);

const pageSizeModel = computed<PageSizeOption>({
  get() {
    return (
      pageSizeDropdownOptions.value.find((o) => o.value === props.pageSize) ||
      pageSizeDropdownOptions.value[0]
    );
  },
  set(option) {
    emit("update:pageSize", option.value);
    emit("update:page", 1);
  },
});

/* -----------------------------
   Derived values
------------------------------ */
const totalPages = computed(() => Math.max(1, Math.ceil(props.total / props.pageSize)));

const start = computed(() =>
  props.total === 0 ? 0 : (props.page - 1) * props.pageSize + 1
);

const end = computed(() => Math.min(props.page * props.pageSize, props.total));

/* -----------------------------
   Navigation
------------------------------ */
function goTo(page: number) {
  if (page < 1 || page > totalPages.value) return;
  emit("update:page", page);
}

function handlePageClick(page?: number) {
  if (!page) return;
  goTo(page);
}

/* -----------------------------
   Truncated pages
------------------------------ */
const pages = computed(() => {
  const result: Array<{
    key: string;
    label: string;
    page?: number;
    ellipsis?: boolean;
  }> = [];

  const total = totalPages.value;
  const current = props.page;
  const sibling = props.siblingCount;

  const startPage = Math.max(2, current - sibling);
  const endPage = Math.min(total - 1, current + sibling);

  result.push({ key: "p-1", label: "1", page: 1 });

  if (startPage > 2) result.push({ key: "e-left", label: "…", ellipsis: true });

  for (let p = startPage; p <= endPage; p++) {
    result.push({ key: `p-${p}`, label: String(p), page: p });
  }

  if (endPage < total - 1) result.push({ key: "e-right", label: "…", ellipsis: true });

  if (total > 1) result.push({ key: `p-${total}`, label: String(total), page: total });

  return result;
});
</script>

